'use client';
import { useToast } from '@/hooks/use-toast';
import React, { useState, useEffect } from 'react';
import {
  MapPin,
  University,
  Search,
  Sparkles,
  Rocket,
  Calendar1,
  Building,
  Tag,
  Type,
} from 'lucide-react';
import Image from 'next/image';
import { motion, AnimatePresence } from 'framer-motion';
import EventCard from '@/components/ui/EventCard';
import { EventCategory } from '@/types';
import { useDebounce } from 'use-debounce';
import Link from 'next/link';
import bgImage from '@/public/bg-events.png';
import { Input } from '@/components/ui/input';
import Decorations from '@/components/ui/Decorations';
import { Button } from '@/components/ui/button';
import { useAuth } from '@/context/AuthContext';
import RegisterConfirmationDialog from '@/components/dialog/RegisterConfirmationDialog';
import UnregisterConfirmationDialog from '@/components/dialog/UnregisterConfirmationDialog';
import { FloatingBlobs } from '@/constants/FloatingBlobs';
import { Loading } from '@/components/ui/Loading';
import Pagination from '@/components/ui/Pagination';
import { fetchEvents } from '@/api/events/events';
import NotFound from '@/components/ui/NotFound';
import { filters } from '@/constants/filters';
import SearchInput from '@/components/ui/SearchInput';

const AllEventsPage = ({ className }: React.HTMLAttributes<HTMLDivElement>) => {
  const { toast } = useToast();
  const { token, userRole, detailsProfile } = useAuth();
  const [events, setEvents] = useState<EventCategory[]>([]);
  const [activeFilter, setActiveFilter] = useState<
    'all' | 'upcoming' | 'past' | 'price' | 'free'
  >('all');
  const [searchQuery, setSearchQuery] = useState('');
  const [debouncedQuery] = useDebounce(searchQuery, 300);
  const [loading, setLoading] = useState<boolean>(false);

  const [selectedEvent, setSelectedEvent] = useState<EventCategory | null>(
    null
  );

  const [isUnregisterModalOpen, setIsUnregisterModalOpen] = useState(false);
  const [isRegisterModalOpen, setIsRegisterModalOpen] = useState(false);

  // status new Pagination
  const [currentPage, setCurrentPage] = useState(1); // حالة Pagination الجديدة
  const [totalPages, setTotalPages] = useState(0);
  const [totalItems, setTotalItems] = useState(0);
  const [eventsPerPage] = useState(6); // عدد الأحداث في كل صفحة

  const currentEvents = (events || []).filter((event) => {
    const matchesSearch = event.title
      .toLowerCase()
      .includes(debouncedQuery.toLowerCase());
    const matchesFilter =
      activeFilter === 'all' ||
      (activeFilter === 'upcoming' && event.status === 'upcoming') ||
      (activeFilter === 'past' && event.status === 'past') ||
      (activeFilter === 'price' && event?.price !== 0) ||
      (activeFilter === 'free' && event?.price === 0);

    return matchesSearch && matchesFilter;
  });
  useEffect(() => {
    fetchEvents({
      token,
      currentPage,
      eventsPerPage,
      activeFilter,
      role: 'public',
      toast,
      setLoading,
    }).then((data) => {
      setEvents(
        data.events.map((event: EventCategory) => ({
          ...event,
          isRegistered: event.registeredUsers.filter((element) => {
            element === detailsProfile?._id ? true : false;
          }),
        }))
      );
      setTotalPages(data.totalPages);
      setTotalItems(data.totalItems);
    });
  }, [currentPage, activeFilter]);

  // Change page
  const paginate = (pageNumber: number) => setCurrentPage(pageNumber);

  // Reset page to 1 when filter changes
  useEffect(() => {
    setCurrentPage(1);
  }, [activeFilter]);

  const RegisterUser = async () => {
    if (!selectedEvent) return;
    try {
      const res = await fetch(
        `http://localhost:8080/users/me/events/${selectedEvent._id}/register`,
        {
          method: 'POST',
          headers: {
            Authorization: `Bearer ${token}`,
            'Content-Type': 'application/json',
          },
        }
      );
      const data = await res.json();
      toast({
        title: 'Registration successful',
        description: data?.message || 'An unexpected error occurred.',
        className: 'bg-green-500 text-white border-0',
      });
      if (res.ok) {
        localStorage.setItem(`registered_${selectedEvent._id}`, 'true');
        setEvents((prev) =>
          prev.map((e) =>
            e._id === selectedEvent._id ? { ...e, isRegistered: true } : e
          )
        );

        console.log('data url ', data.url);
        // Status events paid
        if (selectedEvent.price !== 0) {
          window.location.href = data.url;
        }
      }
    } catch (error: any) {
      toast({
        title: 'Error',
        description: error?.message || 'An unexpected error occurred.',
        className: 'bg-red-500 text-white border-0',
      });
    }

    setIsRegisterModalOpen(false);
    setSelectedEvent(null);
  };
  const UnregisterUser = async () => {
    if (!selectedEvent) return;

    try {
      const res = await fetch(
        `http://localhost:8080/users/me/events/${selectedEvent._id}/unregister`,
        {
          method: 'DELETE',
          headers: {
            Authorization: `Bearer ${token}`,
            'Content-Type': 'application/json',
          },
        }
      );

      const data = await res.json();
      toast({
        title: 'Unregistration successful',
        description: data?.message || 'An unexpected error occurred.',
        className: 'bg-green-500 text-white border-0',
      });

      console.log('message', data.message);
      localStorage.removeItem(`registered_${selectedEvent._id}`);
      setEvents((prev) =>
        prev.map((e) =>
          e._id === selectedEvent._id ? { ...e, isRegistered: false } : e
        )
      );
    } catch (error: any) {
      toast({
        title: 'Error',
        description: error?.message || 'An unexpected error occurred.',
        className: 'bg-red-500 text-white border-0',
      });
    }

    setIsUnregisterModalOpen(false);
    setSelectedEvent(null);
  };

  // state Loading
  if (loading) {
    return <Loading />;
  }

  return (
    <main className='bg-white min-h-screen relative overflow-hidden'>
      <section className='relative flex items-center justify-center h-[60vh] py-20 text-center'>
        <div className='absolute inset-0 z-0'>
          <Image
            src={bgImage}
            alt='Modern Purple Background'
            layout='fill'
            objectFit='cover'
            className='brightness-75'
          />
          <div className='absolute inset-0 bg-gradient-to-br from-purple-900/80 via-indigo-900/60 to-pink-900/40' />
          <FloatingBlobs />
        </div>

        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.3 }}
          className='relative z-10'
        >
          <motion.h1
            animate={{
              backgroundPosition: ['0% 50%', '100% 50%', '0% 50%'],
            }}
            transition={{
              duration: 6,
              repeat: Infinity,
            }}
            className='text-5xl md:text-7xl font-bold bg-clip-text text-transparent 
                            bg-gradient-to-r from-pink-400 via-purple-400 to-indigo-400 mb-6'
          >
            All Events
          </motion.h1>

          <motion.p
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.8 }}
            className='text-xl text-purple-100/90 font-light max-w-2xl mx-auto px-4
                            drop-shadow-lg'
          >
            Discover curated events blending education, networking, and
            entertainment. Explore unique experiences tailored for modern
            enthusiasts.
          </motion.p>

          <motion.div
            initial={{ scale: 0 }}
            animate={{ scale: 1 }}
            className='absolute -top-20 -right-20 opacity-20'
          >
            <Sparkles
              size={200}
              className='text-cyan-400 animate-pulse'
            />
          </motion.div>
        </motion.div>
      </section>

      <div className='max-w-6xl mx-auto px-4 py-10'>
        <div className='flex flex-wrap justify-center items-center gap-4 mb-14'>
                {/* Search Input */}
        <SearchInput
            name='Events'
            searchQuery={searchQuery}
            setSearchQuery={setSearchQuery}
            setCurrentPage={() => setCurrentPage(1)}
          />
          {filters.map(({ label, icon: Icon }, index) => {
            const filterKey = label.toLowerCase() as typeof activeFilter;
            return (
              <motion.button
                key={index}
                whileHover={{
                  scale: 1.05,
                  background: 'linear-gradient(45deg, #9333ea, #4f46e5)',
                }}
                whileTap={{ scale: 0.95 }}
                onClick={() => setActiveFilter(filterKey)}
                className={`relative flex items-center gap-3 px-6 py-3 rounded-full
                                            border-2 backdrop-blur-lg transition-all duration-300 hover:bg-purple-500/20
                                            ${
                                              activeFilter === filterKey
                                                ? 'border-purple-500/30 bg-purple-500 text-black'
                                                : 'border-white/10 bg-purple-900 text-white'
                                            }`}
                style={{
                  boxShadow:
                    activeFilter === filterKey
                      ? '0 4px 24px -2px rgba(165, 180, 252, 0.3)'
                      : 'none',
                }}
              >
                <Icon
                  size={20}
                  className='text-cyan-400'
                />
                <span className='text-sm font-medium tracking-wide'>
                  {label}
                </span>
                {activeFilter === filterKey && (
                  <motion.div
                    className='absolute -bottom-2 h-1 bg-cyan-400 rounded-full'
                    initial={{ scaleX: 0 }}
                    animate={{ scaleX: 1 }}
                    transition={{ type: 'spring', stiffness: 200 }}
                  />
                )}
              </motion.button>
            );
          })}
        </div>
        <div className='flex justify-center text-center'>
          <h2 className='border-white/10 bg-purple-900/90 text-white px-5 py-3 rounded-full mb-6 shadow-sm'>
            Total events {totalItems}
          </h2>
        </div>

        {currentEvents?.length > 0 ? (
          <motion.div
            className='grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 md:gap-8'
            initial='hidden'
            animate='visible'
            variants={{
              hidden: { opacity: 0 },
              visible: {
                opacity: 1,
                transition: {
                  staggerChildren: 0.1,
                  delayChildren: 0.2,
                },
              },
            }}
          >
            <AnimatePresence>
              {currentEvents ? (
                <>
                  {' '}
                  {currentEvents?.map((event, index) => (
                    <motion.div
                      key={index}
                      variants={{ hidden: { opacity: 0, y: 20 }, visible: { opacity: 1, y: 0 } }}
                      whileHover={{ y: -5, transition: { type: 'spring', stiffness: 300 } }}
                      className='relative group'
                    >
                      <EventCard
                        event={event}
                        href={`events/${event._id}`}
                        className='transition-all duration-300 group-hover:shadow-xl group-hover:shadow-purple-500/20 group-hover:border-cyan-400/30'
                        footer={
                          <div className='flex items-center gap-3'>
                            {userRole === 'user' && (
                              <Button
                                variant='outline'
                                className={`flex items-center gap-2 text-white ${event.isRegistered ? 'bg-red-600' : 'bg-purple-500'}`}
                                onClick={() => {
                                  setSelectedEvent(event);
                                  if (event.isRegistered) {
                                    setIsUnregisterModalOpen(true);
                                  } else {
                                    setIsRegisterModalOpen(true);
                                  }
                                }}
                              >
                                {event.isRegistered ? 'Unregister' : 'Register'}
                              </Button>
                            )}
                            {typeof event.price === 'number' && (
                                <span className='bg-purple-50 text-purple-800 font-medium px-3 py-1 rounded-full text-sm shadow-sm'>
                                {event.price === 0 ? 'FREE' : `${event.price} UE`}
                                </span>
                            )}
                          </div>
                        }
                      />
                      <motion.div
                        initial={{ scale: 0 }}
                        animate={{ scale: 1 }}
                        className='absolute top-2 right-2 p-2 bg-purple-600/80 rounded-full backdrop-blur-sm'
                      >
                      </motion.div>
                    </motion.div>
                  ))}
                </>
              ) : (
                <NotFound message='No events found' />
              )}
            </AnimatePresence>
          </motion.div>
        ) : (
          <NotFound message='No events found' />
        )}
      </div>

        {/* Pagination Controls */}
        {currentEvents.length > 0 && (
          <Pagination
            currentPage={currentPage}
            totalPages={totalPages}
            totalItems={totalItems}
            paginate={paginate}
          />
        )}
      {/* Decorations */}
      <Decorations />
      <RegisterConfirmationDialog
        open={isRegisterModalOpen}
        onOpenChange={setIsRegisterModalOpen}
        onConfirm={RegisterUser}
        event={selectedEvent}
      />
      <UnregisterConfirmationDialog
        open={isUnregisterModalOpen}
        onOpenChange={setIsUnregisterModalOpen}
        onConfirm={UnregisterUser}
        event={selectedEvent}
      />
    </main>
  );
};
export default AllEventsPage;
