'use client';
import { motion, AnimatePresence } from 'framer-motion';
import Image from 'next/image';
import Link from 'next/link';
import { cn } from '@/lib/utils';
import { EventCategory } from '@/types';
import { Calendar1, MapPin, Tag, User2, Edit3, Trash2, Download, ShieldCheck, Workflow } from 'lucide-react';
import { ReactNode, useState, useEffect, useRef } from 'react';

type EventCardProps = {
  event: EventCategory;
  href?: string;
  footer?: ReactNode;
  className?: string;
  'aria-label'?: string;
  // admin actions
  isAdmin?: boolean;
  onEdit?: () => void;
  onDelete?: () => void;
  onStatusChange?: () => void;
  onDownloadInvoice?: () => void;
  onApprove?: () => void;
  onReject?: () => void;
  adminActionsMode?: 'buttons' | 'menu';
};

const EventCard = ({ event, href, footer, className, 'aria-label': ariaLabel, isAdmin, onEdit, onDelete, onStatusChange, onDownloadInvoice, onApprove, onReject, adminActionsMode = 'buttons' }: EventCardProps) => {
  const baseURL = 'http://localhost:8080';
  const src = encodeURI(`${baseURL}/${event?.image?.replace(/\\/g, '/')}`);
  const detailsHref = href || `/events/${event._id}`;

  return (
    <motion.article
      role='article'
      aria-labelledby={`event-${event._id}-title`}
      aria-label={ariaLabel || event.title}
      initial={{ opacity: 0, y: 16 }}
      animate={{ opacity: 1, y: 0 }}
      whileHover={{ scale: 1.01 }}
      transition={{ type: 'spring', stiffness: 220, damping: 20 }}
      className={cn(
        'group relative overflow-hidden rounded-2xl border border-purple-100 bg-white shadow-sm hover:shadow-xl transition-all',
        className
      )}
    >
      {/* Admin Controls */}
      {(isAdmin || onDownloadInvoice) && (
        <motion.div
          initial={{ opacity: 0, y: -6 }}
          animate={{ opacity: 1, y: 0 }}
          className='absolute z-20 top-2 right-2'
        >
          {isAdmin && adminActionsMode === 'menu' ? (
            <AdminMenu
              onApprove={onApprove}
              onReject={onReject}
              onStatusChange={onStatusChange}
              onEdit={onEdit}
              onDelete={onDelete}
              onDownloadInvoice={onDownloadInvoice}
            />
          ) : (
            <div className='flex items-center gap-1 sm:gap-2'>
              {isAdmin && (
                <>
                  <button type='button' onClick={onApprove} aria-label='Approve' className='inline-flex items-center justify-center rounded-full bg-white/90 hover:bg-white text-green-700 ring-1 ring-inset ring-green-200 shadow px-2.5 py-1'>
                    <ShieldCheck className='h-4 w-4' />
                  </button>
                  <button type='button' onClick={onReject} aria-label='Reject' className='inline-flex items-center justify-center rounded-full bg-white/90 hover:bg-white text-red-600 ring-1 ring-inset ring-red-200 shadow px-2.5 py-1'>
                    <Workflow className='h-4 w-4 rotate-180' />
                  </button>
                  <button type='button' onClick={onStatusChange} aria-label='Change status' className='inline-flex items-center justify-center rounded-full bg-white/90 hover:bg-white text-purple-700 ring-1 ring-inset ring-purple-200 shadow px-2.5 py-1'>
                    <Workflow className='h-4 w-4' />
                  </button>
                  <button type='button' onClick={onEdit} aria-label='Edit' className='inline-flex items-center justify-center rounded-full bg-white/90 hover:bg-white text-purple-700 ring-1 ring-inset ring-purple-200 shadow px-2.5 py-1'>
                    <Edit3 className='h-4 w-4' />
                  </button>
                  <button type='button' onClick={onDelete} aria-label='Delete' className='inline-flex items-center justify-center rounded-full bg-white/90 hover:bg-white text-red-600 ring-1 ring-inset ring-red-200 shadow px-2.5 py-1'>
                    <Trash2 className='h-4 w-4' />
                  </button>
                </>
              )}
              <button type='button' onClick={onDownloadInvoice} aria-label='Download invoice' className='inline-flex items-center justify-center rounded-full bg-purple-600 hover:bg-purple-700 text-white shadow px-2.5 py-1'>
                <Download className='h-4 w-4' />
              </button>
            </div>
          )}
        </motion.div>
      )}
      {/* Image */}
      <div className='relative h-44 sm:h-52 w-full overflow-hidden'>
        <Image
          src={src}
          alt={event.title || 'Event image'}
          fill
          sizes='(max-width: 640px) 100vw, 33vw'
          className='object-cover transition-transform duration-500 group-hover:scale-105'
          priority={false}
        />
        <div className='absolute inset-0 bg-gradient-to-t from-black/60 via-black/20 to-transparent' />

        {/* Top badges */}
        <div className='absolute top-2 left-2 flex items-center gap-2'>
          {typeof event.price === 'number' ? (
            <span className='rounded-md bg-purple-600/90 px-2 py-0.5 text-xs font-semibold text-white shadow'>
              {event.price === 0 ? 'FREE' : `${event.price} UE`}
            </span>
          ) : null}
          {event.category?.name ? (
            <span className='inline-flex items-center gap-1 rounded-md bg-white/90 px-2 py-0.5 text-xs font-medium text-purple-700 ring-1 ring-inset ring-purple-200'>
              <Tag className='h-3 w-3' /> {event.category.name}
                            </span>
          ) : null}
                          </div>
                        </div>

      {/* Body */}
      <div className='p-4 sm:p-5'>
        <Link href={detailsHref} aria-label={`View details for ${event.title}`}>
          <h3 id={`event-${event._id}-title`} className='text-base sm:text-lg font-semibold tracking-tight text-purple-900 line-clamp-2 hover:underline underline-offset-4'>
                                {event.title}
                              </h3>
        </Link>
        <p className='mt-2 line-clamp-2 text-xs sm:text-sm text-gray-600'>
          {event.description}
        </p>

        <div className='mt-4 grid grid-cols-1 xs:grid-cols-2 gap-2 text-xs sm:text-sm text-gray-700'>
          <div className='inline-flex items-center gap-2'>
            <Calendar1 className='h-4 w-4 text-purple-600' />
            <span>{event.date ? event.date : `${event.startDate} - ${event.endDate}`}</span>
                          </div>
          <div className='inline-flex items-center gap-2'>
            <MapPin className='h-4 w-4 text-purple-600' />
                            <span className='truncate'>{event.location}</span>
                          </div>
          {event.host ? (
            <div className='inline-flex items-center gap-2'>
              <User2 className='h-4 w-4 text-purple-600' />
              <span className='truncate'>{String(event.host)}</span>
                        </div>
          ) : null}
                        </div>

        <div className='mt-4 flex items-center justify-between'>
          <Link
            href={detailsHref}
            className='inline-flex items-center rounded-full bg-purple-600 px-4 py-2 text-xs sm:text-sm font-medium text-white shadow hover:bg-purple-700 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-purple-400 transition-colors'
          >
            View Details
                            </Link>
          {footer}
                    </div>
      </div>
    </motion.article>
  );
};

export default EventCard;

// Compact Admin Menu component
function AdminMenu({ onApprove, onReject, onStatusChange, onEdit, onDelete, onDownloadInvoice }: {
  onApprove?: () => void;
  onReject?: () => void;
  onStatusChange?: () => void;
  onEdit?: () => void;
  onDelete?: () => void;
  onDownloadInvoice?: () => void;
}) {
  const [open, setOpen] = useState(false);
  const menuRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (!open) return;
      if (menuRef.current && !menuRef.current.contains(e.target as Node)) {
        setOpen(false);
      }
    };
    const handleKey = (e: KeyboardEvent) => {
      if (!open) return;
      if (e.key === 'Escape') setOpen(false);
    };
    document.addEventListener('mousedown', handleClickOutside);
    document.addEventListener('keydown', handleKey);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
      document.removeEventListener('keydown', handleKey);
    };
  }, [open]);

  return (
    <div ref={menuRef} className='relative'>
      <button
        type='button'
        aria-haspopup='menu'
        aria-expanded={open}
        onClick={() => setOpen((v) => !v)}
        className='inline-flex items-center justify-center rounded-full bg-purple-600 hover:bg-purple-700 text-white shadow px-3 py-1 text-xs'
      >
        Manage
      </button>
      <AnimatePresence>
        {open && (
          <motion.ul
            initial={{ opacity: 0, y: -4 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -4 }}
            role='menu'
            className='absolute right-0 mt-2 w-44 rounded-lg border border-purple-100 bg-white shadow-xl z-30 p-1'
          >
            <li>
              <button role='menuitem' onClick={() => { setOpen(false); onApprove?.(); }} className='w-full text-left px-3 py-2 rounded-md hover:bg-purple-50 text-green-700 text-sm'>Approve</button>
            </li>
            <li>
              <button role='menuitem' onClick={() => { setOpen(false); onReject?.(); }} className='w-full text-left px-3 py-2 rounded-md hover:bg-purple-50 text-red-700 text-sm'>Reject</button>
            </li>
            <li>
              <button role='menuitem' onClick={() => { setOpen(false); onStatusChange?.(); }} className='w-full text-left px-3 py-2 rounded-md hover:bg-purple-50 text-purple-700 text-sm'>Change Status</button>
            </li>
            <li>
              <button role='menuitem' onClick={() => { setOpen(false); onEdit?.(); }} className='w-full text-left px-3 py-2 rounded-md hover:bg-purple-50 text-gray-800 text-sm'>Edit</button>
            </li>
            <li>
              <button role='menuitem' onClick={() => { setOpen(false); onDelete?.(); }} className='w-full text-left px-3 py-2 rounded-md hover:bg-purple-50 text-red-600 text-sm'>Delete</button>
            </li>
            <li>
              <button role='menuitem' onClick={() => { setOpen(false); onDownloadInvoice?.(); }} className='w-full text-left px-3 py-2 rounded-md hover:bg-purple-50 text-purple-800 text-sm'>Download Invoice</button>
            </li>
          </motion.ul>
        )}
      </AnimatePresence>
    </div>
  );
}
